import java.lang.reflect.Method;

public class GsonToJsonTest {

    private Gson gson;

    @BeforeEach
    public void setUp() {
        gson = new Gson();
    }

    @Test
    public void testToJson_withNull_returnsJsonNull() throws Exception {
        // Invoke private toJson(JsonElement) via reflection to verify output for null input
        Method toJsonJsonElementMethod = Gson.class.getDeclaredMethod("toJson", com.google.gson.JsonElement.class);
        toJsonJsonElementMethod.setAccessible(true);

        String result = (String) toJsonJsonElementMethod.invoke(gson, JsonNull.INSTANCE);
        assertNotNull(result);
        assertEquals("null", result);
    }

    @Test
    public void testToJson_withNonNullObject_returnsJsonString() {
        String src = "test string";

        String json = gson.toJson(src);

        assertNotNull(json);
        assertEquals("\"test string\"", json);
    }

    @Test
    public void testToJson_withInteger_returnsJsonString() {
        Integer src = 123;

        String json = gson.toJson(src);

        assertNotNull(json);
        assertEquals("123", json);
    }

    @Test
    public void testToJson_withCustomObject_returnsJsonString() {
        TestClass testObj = new TestClass();
        testObj.field = "value";

        String json = gson.toJson(testObj);

        assertNotNull(json);
        assertTrue(json.contains("value"));
        assertTrue(json.startsWith("{"));
        assertTrue(json.endsWith("}"));
    }

    @Test
    public void testToJson_reflectionInvokeToJsonObjectClass() throws Exception {
        Method toJsonObjectClassMethod = Gson.class.getDeclaredMethod("toJson", Object.class, java.lang.reflect.Type.class);
        toJsonObjectClassMethod.setAccessible(true);

        String input = "reflection test";
        String result = (String) toJsonObjectClassMethod.invoke(gson, input, String.class);

        assertNotNull(result);
        assertEquals("\"reflection test\"", result);
    }

    static class TestClass {
        String field;
    }
}
